#!/usr/bin/env python3
import sys
from atcoder import dsu
from bisect import bisect_left
from collections import defaultdict
from collections import deque
# import pypyjit
# pypyjit.set_param(inlining=0)     # or pypyjit.set_param('max_unroll_recursion=-1')

sys.setrecursionlimit(10 ** 6)

INF = 2 ** 64 - 1


# Generated by 2.16.0 https://github.com/kyuridenamida/atcoder-tools  (tips: You use the default template now. You can remove this line by using your custom template)
def main():
    T = int(input())

    for _ in range(T):
        N, D = map(int, input().split())
        A = list(map(int, input().split()))
        B = list(map(int, input().split()))

        que = deque()

        for idx, (a, b) in enumerate(zip(A, B)):
            for _ in range(a):
                que.append(idx)
            for _ in range(b):
                que.popleft()
            while que:
                if que[0] != idx - D:
                    break
                que.popleft()

        print(len(que))


if __name__ == '__main__':
    main()
